CREATE TABLE RIROCSPRODLOOKUP ( code char(30) description 'CODE', bbedate date description 'BBEDATE', whshelf Float description 'WHSHELF', exclude char(1) description 'EXCLUDE', presellonly char(1) description 'PRESELLONLY', brand char(35) description 'BRAND', maingroup char(35) description 'MAINGROUP', subgroup char(35) description 'SUBGROUP', subsubgroup char(35) description 'SUBSUBGROUP', substituteProductCode char(30) description 'SUBSTITUTEPRODUCTCODE', alternativeProductCode1 char(30) description 'ALTERNATIVEPRODUCTCODE1', alternativeProductCode2 char(30) description 'ALTERNATIVEPRODUCTCODE2', alternativeProductCode3 char(30) description 'ALTERNATIVEPRODUCTCODE3', alternativeProductCode4 char(30) description 'ALTERNATIVEPRODUCTCODE4', discontinued char(1) description 'DISCONTINUED', brandname char(40) description 'BRANDNAME', LongDesc char(120) description 'LONGDESC', PRIMARY KEY (code));

-- line 48
INSERT INTO RIROCSPRODLOOKUP SELECT product.code, product.uf_bberotdate, product.uf_wh_shelf, product.PRUSER03, product.UF_PSONLY, brands.desc AS BRAND, main_groups.desc AS MAIN_GROUP, sub_groups.desc as SUB_GROUP, sub_sub_groups.desc as SUB_SUB_GROUP, product.uf_suppliersub AS SUBSTITUTE_PRODUCT_CODE, product.uf_rialt1 AS ALTERNATIVE_PRODUCT_CODE_1, product.uf_rialt2 AS ALTERNATIVE_PRODUCT_CODE_2, product.uf_rialt3 AS ALTERNATIVE_PRODUCT_CODE_3, product.uf_rialt4 AS ALTERNATIVE_PRODUCT_CODE_4, product.pruser01 AS DISCONTINUED, niingred.nibrand, niingred.nildesc from product left join prodgrp brands on left(product.code,1) +'UK' = brands.code left join prodgrp main_groups on left(product.group,2) + 'UK' = main_groups.code left join prodgrp sub_groups on left(product.group,4) + 'UK' = sub_groups.code left join prodgrp sub_sub_groups on left(product.group,6) + 'UK' = sub_sub_groups.code left join niingred on product.uf_ibarcode = niingred.niean where niingred.nilang = 'ENGLISH';

-- line 75
select analysis.sacust as CUSTOMER_CODE, max(ANALYSIS.SADATE) as INVOICE_DATE, analysis.saterr as TERRITORY, analysis.saproduct as PRODUCT_CODE, sum(analysis.saorgqty) as QUANTITY, count(analysis.saref) as FREQUENCY, RIROCSPRODLOOKUP.BRAND as BRAND, RIROCSPRODLOOKUP.BBEDATE, RIROCSPRODLOOKUP.WHSHELF, RIROCSPRODLOOKUP.BRANDNAME, RIROCSPRODLOOKUP.MAINGROUP as MAIN_GROUP, RIROCSPRODLOOKUP.SUBGROUP as SUB_GROUP, RIROCSPRODLOOKUP.SUBSUBGROUP as SUB_SUB_GROUP, RIROCSPRODLOOKUP.LONGDESC from analysis join RIROCSPRODLOOKUP on analysis.saproduct = RIROCSPRODLOOKUP.CODE where analysis.sacredit = '0' and sadate >= ? and left(analysis.saproduct,1) <> '*' and RIROCSPRODLOOKUP.PRESELLONLY <> 'Y' AND (DISCONTINUED = 'N' OR (DISCONTINUED = 'Y' AND SADATE > ?) OR (DISCONTINUED = 'Y' AND ( SUBSTITUTEPRODUCTCODE IS NOT NULL OR ALTERNATIVEPRODUCTCODE1 IS NOT NULL OR ALTERNATIVEPRODUCTCODE2 IS NOT NULL OR ALTERNATIVEPRODUCTCODE3 IS NOT NULL OR ALTERNATIVEPRODUCTCODE4 IS NOT NULL ))) Group by CUSTOMER_CODE, TERRITORY, PRODUCT_CODE, BRAND, MAIN_GROUP, SUB_GROUP, RIROCSPRODLOOKUP.LONGDESC;

